import{_ as t,o as i,c as o,ae as l}from"./chunks/framework.RRduUuAx.js";const a="/screenshots/tkg2.png",n="/screenshots/tkg1.png",m=JSON.parse('{"title":"Compiling your own kernel","description":"","frontmatter":{},"headers":[],"relativePath":"miscellaneous/kernel.md","filePath":"miscellaneous/kernel.md","lastUpdated":1777870860000}'),r={name:"miscellaneous/kernel.md"};function s(h,e,p,u,c,d){return i(),o("div",null,[...e[0]||(e[0]=[l(`<h1 id="compiling-your-own-kernel" tabindex="-1">Compiling your own kernel <a class="header-anchor" href="#compiling-your-own-kernel" aria-label="Permalink to &quot;Compiling your own kernel&quot;">​</a></h1><p>This page contains content on how to compile your own kernel.</p><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>If you cannot understand any of this get the fuck out.</p></div><h2 id="rquirements" tabindex="-1">Rquirements: <a class="header-anchor" href="#rquirements" aria-label="Permalink to &quot;Rquirements:&quot;">​</a></h2><ul><li><p>Semi-Decent Machine. The ps4 itself can be used as well.</p></li><li><p>Reading capability.</p></li><li><p>Patience.</p></li></ul><h2 id="where-to-start" tabindex="-1">Where to start? <a class="header-anchor" href="#where-to-start" aria-label="Permalink to &quot;Where to start?&quot;">​</a></h2><ul><li>First you should start by choosing the method you will use to compile the kernel with.</li></ul><h2 id="which-methods-are-available" tabindex="-1">Which methods are available? <a class="header-anchor" href="#which-methods-are-available" aria-label="Permalink to &quot;Which methods are available?&quot;">​</a></h2><ul><li>You can manually compile using commands by following the <a href="https://wiki.archlinux.org/title/Kernel/Arch_build_system" target="_blank" rel="noreferrer">archwiki</a>. Or you can do the far more user friendly approach by using <a href="https://github.com/Frogging-Family/linux-tkg" target="_blank" rel="noreferrer">linux-tkg</a>. In this page only linux-tkg will be covered as its far more user friend and just easier to use.</li></ul><h2 id="step-1-setup" tabindex="-1">Step 1 - Setup <a class="header-anchor" href="#step-1-setup" aria-label="Permalink to &quot;Step 1 - Setup&quot;">​</a></h2><ul><li><p>First clone the linux-tkg repo.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://github.com/Frogging-Family/linux-tkg.git</span></span></code></pre></div></li><li><p>Download the modified PKGBUILD file and place it into the directory.</p></li><li><p>Download using this link <a href="https://github.com/FlyingPhantom/ps4-linux-tutorial/blob/main/PS4%20Linux/PKGBUILD" target="_blank" rel="noreferrer">here</a>.</p></li><li><p>You will also need to install couple packages needed to compile you can copy the provided command:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>yay -S --needed base-devel git ccache schedtool clang lld llvm \\</span></span>
<span class="line"><span>bison xmlto docbook-xsl inetutils bc libelf pahole patchutils flex \\</span></span>
<span class="line"><span>python-sphinx python-sphinx_rtd_theme graphviz imagemagick cpio \\</span></span>
<span class="line"><span>perl tar xz wget --noconfirm</span></span></code></pre></div></li></ul><h2 id="step-2-configuring-the-linux-tkg-project" tabindex="-1">Step 2 - Configuring the linux-tkg project <a class="header-anchor" href="#step-2-configuring-the-linux-tkg-project" aria-label="Permalink to &quot;Step 2 - Configuring the linux-tkg project&quot;">​</a></h2><ul><li><p>Go into $HOME/.config and make a directory called <em>frogminer</em></p></li><li><p>After that go back to <em>linux-tkg</em> and copy the &quot;customization.cfg&quot; into the <em>.config/frogminer</em> directory but rename the file to &quot;linux-tkg.cfg&quot;.</p></li><li><p>Open the config file and change &quot;_git_mirror=&quot; to &quot;_git_mirror=&quot;<a href="https://github.com/feeRnt/ps4-linux-12xx.git" target="_blank" rel="noreferrer">https://github.com/feeRnt/ps4-linux-12xx.git</a>&quot;</p></li></ul><blockquote><p><strong>NOTE: this kernel is only aoelia-belize go to his repo to find kernels for baikal.</strong></p></blockquote><ul><li><p>This will clone the 6.15.4 kernel wen you select it.</p></li><li><p>Example with images will be provided here.</p></li></ul><blockquote><p><strong>NOTE: Im using offline mode here so you will not see other kernels besides ones that have been cloned.</strong></p></blockquote><img src="`+a+'" width="75%"><img src="'+n+'" width="75%"><blockquote><p><strong>NOTE:Fixing the pkgbuild</strong></p></blockquote><blockquote><ul><li>The linux-tkg project does not allow the option for kernel output to be compiled as bzImage, i made a pr request but it has been rejected so for now you will need to use a modified PKGBUILD file.</li></ul></blockquote><blockquote><ul><li>This is only for arch because its the distro i use i dont know for other distros but you will have to modify ./install.sh script if you dont use arch.</li></ul></blockquote><blockquote><ul><li>You can download the follow modded PKGBUILD file from this link <a href="https://github.com/FlyingPhantom/ps4-linux-tutorial/blob/main/PS4%20Linux/PKGBUILD" target="_blank" rel="noreferrer">here</a>.</li></ul></blockquote><h2 id="step-3-recommended-settings" tabindex="-1">Step 3 - Recommended settings. <a class="header-anchor" href="#step-3-recommended-settings" aria-label="Permalink to &quot;Step 3 - Recommended settings.&quot;">​</a></h2><ul><li><p>Config for linux-tkg.cfg will be provided <a href="https://github.com/FlyingPhantom/ps4-linux-tutorial/blob/main/PS4%20Linux/linux-tkg.cfg" target="_blank" rel="noreferrer">here</a>. I will call this the recommended config because it has been tuned for the ps4 and minimizing compile time. If you wanna lower the compile times even more check out <a href="https://wiki.archlinux.org/title/Modprobed-db" target="_blank" rel="noreferrer">modprobed-db</a> on archwiki.</p></li><li><p>The config will be used automatically if you followed up the Step 1 of the guide.</p></li><li><p>Cd in the the linux-tkg with this command:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd linux-tkg</span></span></code></pre></div></li><li><p>Now run the <em>makepkg -o</em> to check if everything is working fine then run <em>makepkg -s</em> command to and follow the instructions of the linux-tkg to build the kernel.</p></li></ul>',24)])])}const b=t(r,[["render",s]]);export{m as __pageData,b as default};
